example.code:
// Agent pattern: fetch list IDs once, then create card
const lists = await fetch(
  `https://api.trello.com/1/boards/${BOARD_ID}/lists?key=${KEY}&token=${TOKEN}`
).then(r => r.json());
const backlogId = lists.find(l => l.name === "Backlog").id;

await fetch(`https://api.trello.com/1/cards?key=${KEY}&token=${TOKEN}`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    name: 'Add OAuth integration',
    desc: '## Feature\n...',
    idList: backlogId,
    idLabels: [FEATURE_LABEL_ID]
  })
});
